PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE TokenEntity (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    coin_uid TEXT NOT NULL,
    blockchain_uid TEXT NOT NULL,
    type TEXT NOT NULL,
    decimals INTEGER,
    reference TEXT,
    FOREIGN KEY (coin_uid) REFERENCES Coin (uid),
    FOREIGN KEY (blockchain_uid) REFERENCES BlockchainEntity (uid)
);
COMMIT;